// // This module implements a combinational logic circuit that outputs X when any two of the inputs A1, A2, and A3 are true, or when B1 is true and C1 is false.
module top_module(
    input A1,
    input A2,
    input A3,
    input B1,
    input C1,
    output X
);assign X = (A1 & A2 & A3) | (B1 & ~C1);

endmodule
